<x-layouts.app><x-breadcrumb>Patrimonio / Ativos</x-breadcrumb><div class="mb-5 flex items-start justify-between gap-4"><div><h1 class="font-[Sora] text-2xl font-bold">Ativos</h1><p class="mt-1 text-sm text-gray-500">Cadastro patrimonial inicial por tenant.</p></div>@can('create', \App\Domain\Assets\Models\Asset::class)<x-button onclick="location.href='{{ route('assets.create') }}'">Cadastrar ativo</x-button>@endcan</div><x-filter-panel method="GET"><x-input name="asset_number" value="{{ request('asset_number') }}" placeholder="Numero patrimonial"/><x-input name="legacy_number" value="{{ request('legacy_number') }}" placeholder="Numero legado"/><x-input name="description" value="{{ request('description') }}" placeholder="Descricao"/><x-select name="category"><option value="">Categoria</option>@foreach($categories as $category)<option value="{{ $category->public_id }}" @selected(request('category') === $category->public_id)>{{ $category->name }}</option>@endforeach</x-select><x-select name="type"><option value="">Tipo</option>@foreach($types as $type)<option value="{{ $type->public_id }}" @selected(request('type') === $type->public_id)>{{ $type->name }}</option>@endforeach</x-select><x-select name="brand"><option value="">Marca</option>@foreach($brands as $brand)<option value="{{ $brand->public_id }}" @selected(request('brand') === $brand->public_id)>{{ $brand->name }}</option>@endforeach</x-select><x-select name="model"><option value="">Modelo</option>@foreach($models as $model)<option value="{{ $model->public_id }}" @selected(request('model') === $model->public_id)>{{ $model->name }}</option>@endforeach</x-select><x-select name="organizational_unit"><option value="">Unidade administrativa</option>@foreach($organizationalUnits as $unit)<option value="{{ $unit->public_id }}" @selected(request('organizational_unit') === $unit->public_id)>{{ $unit->name }}</option>@endforeach</x-select><x-select name="condition"><option value="">Condicao</option>@foreach($conditions as